// Bar — a horizontal value bar: an optional label, then a rounded track that
// fills to `value` (0–100). A PLACEHOLDER component (see composition.md §1a):
// coherent and restyleable — override `tint` for the fill — but not the final
// widget; the real component library is a later, dedicated effort.

class Bar extends View [ height = 28,
    label: string = "",
    value: number = 0,
    tint:  Color  = #4C8DFF,
    lead:  number = { this.label == "" ? 0 : 96 },
    cap: Text [ y = 5, fontSize = 14, textColor = #8A9BA6, text = { classroot.label } ],
    rail: View [ x = { classroot.lead }, width = { parent.width - classroot.lead },
        height = { parent.height }, cornerRadius = 6, fill = #0A1119,
        bar: View [ height = { parent.height }, cornerRadius = 6, fill = { classroot.tint },
            width = { parent.width * classroot.value / 100 } ],
        ],
    ]

App [ facts: Dataset { { "rows": [
        { "label": "reactive", "n": 92 },
        { "label": "compiled", "n": 78 },
        { "label": "small",    "n": 64 } ] } },
    View [ x = 28, y = 26, datapath = { parent.facts.value },
        layout: SimpleLayout [ axis = y, spacing = 16 ],
        Bar [ width = 300, datapath = :rows[], label = :label, value = :n ],
        ],
    ]
